#include<bits/stdc++.h>
using namespace std;
const int maxn = 500+5;
int n,a[maxn],f[maxn][maxn],dp[maxn];
bool v[maxn],flag=0;
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		f[i][i]=a[i];
		if(v[a[i]])flag=1;
		v[a[i]]=1;
	}
	
	if(flag)
	{
		for(int len=2;len<=n;len++)
		{
			for(int l=1;l+len-1<=n;l++)
			{
				int r=l+len-1;
				for(int k=l;k<r;k++)
				{
					if(f[l][k]>0&&f[l][k]==f[k+1][r])f[l][r]+=f[l][k]+1;
				}
			}
		}
		memset(dp,0x3f,sizeof(dp));
		dp[0]=0;
		for(int i=1;i<=n;i++)
		{
			for(int j=1;j<=i;j++)
			{
				if(f[j][i]>0)dp[i]=min(dp[j-1]+1,dp[i]);
			}
		}
		cout<<dp[n];
	}
	else cout<<n;
	return 0;
}
